import java.util.Arrays;

public int[] findSecondGreater(int[] nums) {
    int n = nums.length;
    int[] answer = new int[n];
    Arrays.fill(answer, -1);

    for (int i = 0; i < n; i++) {
        int k = -1;
        for (int j = i + 1; j < n; j++) {
            if (nums[j] > nums[i]) {
                if (k == -1) {
                    k = j;
                } else {
                    answer[i] = nums[j];
                    break;
                }
            }
        }
    }

    return answer;
}
```

